#\n# @lc app=leetcode id=3615 lang=python3\n#\n# [3615] Longest Palindromic Path in Graph\n#\n\n# @lc code=start\nclass Solution:\n    def maxLen(self, n: int, edges: List[List[int]], label: str) -> int:\n        import collections\n        \n        def can_form_palindrome(count):\n            odd_count = sum(v % 2 for v in count.values())\n            return odd_count <= 1\n\n        adj = collections.defaultdict(list)\n        for u, v in edges:\n            adj[u].append(v)\n            adj[v].append(u)\n        \n        max_length = 0\n        \n        def dfs(node, visited, count):\n            nonlocal max_length\n            count[label[node]] += 1\n            if can_form_palindrome(count):\n                max_length = max(max_length, sum(count.values()))\n            visited.add(node)\n            for nei in adj[node]:\n                if nei not in visited:\n                    dfs(nei, visited, count)\n            # Backtrack by removing current node from path and visited set\n            count[label[node]] -= 1\n            visited.remove(node)\ndfs(start_node, set(), collections.Counter()) # @lc code=end